INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Calicut', 'overview', 'Overview > Full Name: National Institute of Technology Calicut (NITC).');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Calicut', 'overview', 'Overview > Location: NIT Campus P.O., Kattangal, Mukkam Road, Kozhikode-673601, Kerala.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Calicut', 'overview', 'Overview > Languages spoken locally: Malayalam, Hindi, English. Languages spoken in college: Malayalam, Telugu, Hindi, Tamil, English.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Calicut', 'overview', 'Overview > Climate: Tropical monsoon climate with high humidity, hot summers, and heavy rainfall.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Calicut', 'transport', 'Transport > Airport: Calicut International Airport, Karipur, Kerala is 20.2 km from NIT Calicut.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Calicut', 'transport', 'Transport > Railway: Kozhikode Railway Station is 19 km from NIT Calicut.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Calicut', 'transport', 'Transport > Bus: NITC Bus Stop is 800 m from NIT Calicut campus.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Calicut', 'restaurants', 'Restaurants > Nearby: Over The Moon (OTM) on Kattangal, Mukkam Road.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Calicut', 'restaurants', 'Restaurants > Delivery Apps: Swiggy Instamart, Dominos, and Zomato are available at NIT Calicut.');
