INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Calicut', 'hostels', 'Hostels > Boys Juniors (1st year): Hostel A, Hostel B, Hostel C (3 sharing per room).');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Calicut', 'hostels', 'Hostels > Boys 2nd/3rd year: Mega Hostels (2 sharing per room).');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Calicut', 'hostels', 'Hostels > Boys 4th year: Old Mega Hostels, Hostel E, Hostel D (single room).');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Calicut', 'hostels', 'Hostels > Boys Summary: 1st years get 3-sharing in A, B, C hostels. 2nd/3rd years get 2-sharing in Mega Hostels. 4th years get single rooms in Old Mega Hostels, E, or D.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Calicut', 'hostels', 'Hostels > Girls: MLH (Mega Ladies Hostel), Hostel F, Hostel G.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Calicut', 'hostels', 'Hostels > Girls Summary: 3 girls hostels at NIT Calicut.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Calicut', 'hostels', 'Hostels > PG: PG1 and PG2 (single room).');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Calicut', 'hostels', 'Hostels > Seat Rent: Rs 12,000 per semester (charged extra, not included in tuition fee totals).');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Calicut', 'mess', 'Mess > Timings: Breakfast 7 AM - 9 AM, Lunch 12 PM - 2 PM, Evening snacks 4 PM - 5 PM, Dinner 7 PM - 9 PM.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Calicut', 'fee_structure', 'Fee Structure > Program: B.Tech 2025-26 batch at NIT Calicut.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Calicut', 'fee_structure', 'Fee Structure > Category 1 (Open/EWS/OBC with family income above Rs 5 lakh + DASA CIWG/MEA): Tuition Fee Rs 62,500 per semester.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Calicut', 'fee_structure', 'Fee Structure > Category 1 Other Fees (Monsoon semester): Rs 19,100 total. Breakdown: Registration Rs 2,000, Examination Rs 2,000, Activities Rs 600, Association & Cultural Rs 1,200, Student Welfare Rs 1,200, Career Development Rs 1,200, Library Rs 4,000, Computing Rs 600, Internet Rs 1,200, Sports Rs 1,200, Health Rs 1,200, Medical Insurance Rs 1,500, Campus Amenities Rs 1,200.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Calicut', 'fee_structure', 'Fee Structure > Category 1 Other Fees (Winter semester): Rs 6,400 total. Only Registration, Examination, Activities, Career Development, and Computing fees are charged in winter semester.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Calicut', 'fee_structure', 'Fee Structure > Category 1 One-time Fees: Rs 61,000 total. Breakdown: Caution Deposit Rs 20,000, Admission Fee Rs 5,000, Campus Development Rs 25,000, Alumni Association Rs 5,000, Convocation Rs 5,000, ID Card Rs 1,000.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Calicut', 'fee_structure', 'Fee Structure > Category 1 Totals: 1st semester (Monsoon) Rs 1,42,600. 2nd semester (Winter) Rs 68,900. Subsequent Monsoon semesters Rs 81,600. Subsequent Winter semesters Rs 68,900.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Calicut', 'fee_structure', 'Fee Structure > Category 2 (Open/EWS/OBC with family income Rs 1-5 lakh): Tuition Fee Rs 20,833 per semester (one-third of full tuition).');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Calicut', 'fee_structure', 'Fee Structure > Category 2 Totals: 1st semester (Monsoon) Rs 1,00,933. 2nd semester (Winter) Rs 27,233.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Calicut', 'fee_structure', 'Fee Structure > Category 3 (Open/EWS/OBC with family income below Rs 1 lakh + SC/ST/PH): Tuition Fee Rs 0 (fully waived).');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Calicut', 'fee_structure', 'Fee Structure > Category 3 Totals: 1st semester (Monsoon) Rs 80,100. 2nd semester (Winter) Rs 6,400.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Calicut', 'fee_structure', 'Fee Structure > DASA Non-CIWG Non-SAARC: Tuition USD 4,000 per semester.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Calicut', 'fee_structure', 'Fee Structure > DASA Non-CIWG SAARC: Tuition USD 2,000 per semester.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Calicut', 'fee_structure', 'Fee Structure > Hostel Seat Rent: Rs 12,000 per semester extra (not included in the above totals). Some fees are annual and charged only in the Monsoon semester.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Calicut', 'wifi', 'WiFi > WiFi and LAN are both available at NIT Calicut.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Calicut', 'attendance', 'Attendance > NIT Calicut has a unique attendance range: Maximum 80%, Minimum 70%. This is different from most NITs which have a flat 75% requirement.');
